const upsertCandidateVote = `-- name: UpsertCandidateVote :one
INSERT INTO "profile_membership_candidate_vote" (
  id, candidate_id, voter_membership_id, score, comment, created_at
) VALUES (
  $1,
  $2,
  $3,
  $4,
  $5,
  NOW()
) ON CONFLICT (candidate_id, voter_membership_id)
DO UPDATE SET
  score = EXCLUDED.score,
  comment = EXCLUDED.comment,
  updated_at = NOW()
RETURNING id, candidate_id, voter_membership_id, score, comment, created_at, updated_at
`

type UpsertCandidateVoteParams struct {
	ID                string         `db:"id" json:"id"`
	CandidateID       string         `db:"candidate_id" json:"candidate_id"`
	VoterMembershipID string         `db:"voter_membership_id" json:"voter_membership_id"`
	Score             int16          `db:"score" json:"score"`
	Comment           sql.NullString `db:"comment" json:"comment"`
}

// UpsertCandidateVote
//
//	INSERT INTO "profile_membership_candidate_vote" (
//	  id, candidate_id, voter_membership_id, score, comment, created_at
//	) VALUES (
//	  $1,
//	  $2,
//	  $3,
//	  $4,
//	  $5,
//	  NOW()
//	) ON CONFLICT (candidate_id, voter_membership_id)
//	DO UPDATE SET
//	  score = EXCLUDED.score,
//	  comment = EXCLUDED.comment,
//	  updated_at = NOW()
//	RETURNING id, candidate_id, voter_membership_id, score, comment, created_at, updated_at
func (q *Queries) UpsertCandidateVote(ctx context.Context, arg UpsertCandidateVoteParams) (*ProfileMembershipCandidateVote, error) {
	row := q.db.QueryRowContext(ctx, upsertCandidateVote,
		arg.ID,
		arg.CandidateID,
		arg.VoterMembershipID,
		arg.Score,
		arg.Comment,
	)
	var i ProfileMembershipCandidateVote
	err := row.Scan(
		&i.ID,
		&i.CandidateID,
		&i.VoterMembershipID,
		&i.Score,
		&i.Comment,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return &i, err
}
